// // This module selects between two 16-bit input signals, in0 and in1, based on the value of the sel input. When sel is high (1), the output out is assigned the value of in0; when sel is low (0), out takes the value of in1.
module top_module(out, in0, in1, sel);input [15:0] in0, in1;
  input sel;
  output [15:0] out;

  assign out = sel ? in1 : in0;endmodule
